import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjSparkChart } from "./OjSparkChart";
export { OjSparkChart };

/**
 * Create an instance of [[OjSparkChart]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojSparkChart(driver, By.id('my-oj-spark-chart'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojSparkChart(driver: DriverLike, by: By): Promise<OjSparkChart> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjSparkChart
  if (!(webEl instanceof OjSparkChart)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-spark-chart>`);
  }
  return webEl;
}

register("oj-spark-chart", OjSparkChart);
